export default App;

export interface NavStep {
  instruction: string;
  detail?: string;
  icon?: 'turn-left' | 'turn-right' | 'straight' | 'stairs-up' | 'stairs-down' | 'destination';
}

export interface LocationData {
  id: string;
  name: string;
  block: string;
  floor: string;
  aliases: string[];
  distance: number; // meters
  estimatedTime: number; // minutes
  steps: NavStep[];
}

export interface FeeStructure {
  id: string;
  course: 'B.Tech' | 'MBA' | 'Diploma';
  branch: string;
  year: '1st' | '2nd' | '3rd' | '4th';
  tuitionFee: number;
  devFee: number;
  total: number;
}

export enum IntentType {
  NAVIGATE = 'NAVIGATE',
  FEE = 'FEE',
  UNKNOWN = 'UNKNOWN'
}

export interface IntentResult {
  type: IntentType;
  entity?: string; // extracted location or course info
  confidence: number;
}

import Fuse from 'fuse.js';
import { LOCATIONS } from '../data/mockData';
import { LocationData } from '../types';

const options = {
  includeScore: true,
  keys: ['name', 'aliases', 'block'],
  threshold: 0.4, // 0.0 is perfect match, 1.0 is match anything
};

const fuse = new Fuse(LOCATIONS, options);

export const searchLocations = (query: string): LocationData[] => {
  if (!query) return [];
  const results = fuse.search(query);
  return results.map(result => result.item);
};

export const getAllLocations = (): LocationData[] => {
  return LOCATIONS.sort((a, b) => a.name.localeCompare(b.name));
};

export const getLocationById = (id: string): LocationData | undefined => {
  return LOCATIONS.find(loc => loc.id === id);
};

// Types for the Web Speech API
interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  start(): void;
  stop(): void;
  abort(): void;
  onstart: (event: Event) => void;
  onend: (event: Event) => void;
  onerror: (event: any) => void;
  onresult: (event: any) => void;
}

interface Window {
  SpeechRecognition: any;
  webkitSpeechRecognition: any;
}

export const startListening = (
  onResult: (text: string) => void,
  onEnd: () => void,
  onError: (error: string) => void
) => {
  const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

  if (!SpeechRecognition) {
    onError('Speech recognition not supported in this browser.');
    return null;
  }

  const recognition: SpeechRecognition = new SpeechRecognition();
  recognition.continuous = false;
  recognition.interimResults = false;
  recognition.lang = 'en-US';

  recognition.onstart = () => {
    // console.log('Listening started...');
  };

  recognition.onresult = (event: any) => {
    const transcript = event.results[0][0].transcript;
    onResult(transcript);
  };

  recognition.onerror = (event: any) => {
    onError(event.error);
  };

  recognition.onend = () => {
    onEnd();
  };

  try {
    recognition.start();
    return recognition;
  } catch (e) {
    onError('Failed to start recognition');
    return null;
  }
};

import React from 'react';
import { NavLink, useLocation } from 'react-router-dom';
import { Home, Map, CircleDollarSign } from 'lucide-react';

