import React, { useState, useEffect, useRef } from 'react';
import { Mic, X, Send, Bot, Loader2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { startListening } from '../services/speechService';
import { IntentType } from '../types';
import toast from 'react-hot-toast';

const Assistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [query, setQuery] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const navigate = useNavigate();

  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  const handleVoiceInput = () => {
    if (isListening) return;
    setIsListening(true);
    startListening(
      (text) => {
        setQuery(text);
        processQuery(text);
      },
      () => setIsListening(false),
      (err) => {
        setIsListening(false);
        toast.error('Voice input failed. Please try again.');
      }
    );
  };

  const processQuery = async (text: string) => {
    setIsProcessing(true);
    const lowerText = text.toLowerCase();

    // Simple Intent Detection Logic
    let intent = IntentType.UNKNOWN;

    // Check for fee related keywords
    if (lowerText.includes('fee') || lowerText.includes('cost') || lowerText.includes('tuition') || lowerText.includes('price')) {
      intent = IntentType.FEE;
    }
    // Check for navigation related keywords
    else if (
      lowerText.includes('where') || 
      lowerText.includes('go to') || 
      lowerText.includes('direction') || 
      lowerText.includes('route') ||
      lowerText.includes('find')
    ) {
      intent = IntentType.NAVIGATE;
    }

    // Artificial delay to simulate "AI" thinking
    setTimeout(() => {
      setIsProcessing(false);
      setIsOpen(false);
      setQuery('');

      if (intent === IntentType.FEE) {
        toast.success("Opening Course Fees...");
        navigate('/fees');
        // Advanced: Could parse course name from query here and pass as state
      } else if (intent === IntentType.NAVIGATE) {
        toast.success("Opening Directions...");
        // Extract potential location
        const locationKeyword = text.replace(/go to|where is|find|direction to|directions for/gi, '').trim();
        navigate('/directions', { state: { initialQuery: locationKeyword } });
      } else {
        toast('I didn\'t quite catch that. Try asking for "Directions" or "Fees".', {
          icon: '🤖',
          duration: 4000
        });
      }
    }, 1000);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) processQuery(query);
  };

  return (
    <>
      {/* Trigger Button */}
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-8 right-8 p-4 rounded-full shadow-2xl transition-all duration-300 z-50 flex items-center gap-2 ${
          isOpen ? 'scale-0 opacity-0' : 'bg-blue-600 text-white hover:bg-blue-700 scale-100 opacity-100'
        }`}
      >
        <Bot size={32} />
        <span className="font-semibold pr-2">May I help you?</span>
      </button>

      {/* Modal/Popup */}
      {isOpen && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-end justify-end sm:items-center sm:justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            {/* Header */}
            <div className="bg-gradient-to-r from-blue-600 to-blue-500 p-6 flex justify-between items-center text-white">
              <div className="flex items-center gap-3">
                <div className="bg-white/20 p-2 rounded-full">
                  <Bot size={24} />
                </div>
                <div>
                  <h3 className="font-bold text-lg">Virtual Assistant</h3>
                  <p className="text-blue-100 text-sm">Ask about fees or directions</p>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-2 rounded-full transition-colors">
                <X size={20} />
              </button>
            </div>

            {/* Body */}
            <div className="p-6">
              <div className="mb-6 space-y-2">
                <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Try asking</p>
                <div className="flex flex-wrap gap-2">
                  <button onClick={() => processQuery("What is the fee for CSE?")} className="px-4 py-2 bg-slate-100 hover:bg-blue-50 text-slate-700 rounded-lg text-sm transition-colors text-left">
                    "What is the fee for CSE?"
                  </button>
                  <button onClick={() => processQuery("Directions to Library")} className="px-4 py-2 bg-slate-100 hover:bg-blue-50 text-slate-700 rounded-lg text-sm transition-colors text-left">
                    "Directions to Library"
                  </button>
                  <button onClick={() => processQuery("Where is the Canteen?")} className="px-4 py-2 bg-slate-100 hover:bg-blue-50 text-slate-700 rounded-lg text-sm transition-colors text-left">
                    "Where is the Canteen?"
                  </button>
                </div>
              </div>

              <form onSubmit={handleSubmit} className="relative">
                <input
                  ref={inputRef}
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder="Type or speak your request..."
                  className="w-full pl-4 pr-24 py-4 bg-slate-50 border-2 border-slate-200 rounded-xl focus:border-blue-500 focus:outline-none text-lg"
                />
                <div className="absolute right-2 top-2 bottom-2 flex gap-1">
                  <button
                    type="button"
                    onClick={handleVoiceInput}
                    className={`p-3 rounded-lg transition-colors ${
                      isListening ? 'bg-red-100 text-red-600 animate-pulse' : 'hover:bg-slate-200 text-slate-500'
                    }`}
                  >
                    <Mic size={24} />
                  </button>
                  <button
                    type="submit"
                    disabled={!query.trim() || isProcessing}
                    className="p-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {isProcessing ? <Loader2 size={24} className="animate-spin" /> : <Send size={24} />}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default Assistant;

import React, { useState, useEffect } from 'react';
import { Search, MapPin, Navigation, Clock, Footprints, Mic, ChevronRight, RotateCcw } from 'lucide-react';
import { QRCodeSVG } from 'qrcode.react';
import { useLocation } from 'react-router-dom';
import { searchLocations, getAllLocations, getLocationById } from '../services/searchService';
import { startListening } from '../services/speechService';
import { LocationData } from '../types';
import toast from 'react-hot-toast';

const Directions: React.FC = () => {
  const routerLoc = useLocation();
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<LocationData[]>([]);
  const [selectedRoute, setSelectedRoute] = useState<LocationData | null>(null);
  const [isListening, setIsListening] = useState(false);

  // Handle intent passing from Assistant
  useEffect(() => {
    if (routerLoc.state && (routerLoc.state as any).initialQuery) {
      const initQ = (routerLoc.state as any).initialQuery;
      setQuery(initQ);
      const matches = searchLocations(initQ);
      if (matches.length > 0) {
        setSelectedRoute(matches[0]);
      } else {
        setResults([]);
        toast.error("Location not found.");
      }
    } else {
      // Default: show all sorted by name
      setResults(getAllLocations());
    }
  }, [routerLoc.state]);

  const handleSearch = (text: string) => {
    setQuery(text);
    if (text.trim() === '') {
      setResults(getAllLocations());
      return;
    }
    const matches = searchLocations(text);
    setResults(matches);
  };

  const startVoiceSearch = () => {
    setIsListening(true);
    startListening(
      (text) => {
        handleSearch(text);
        const matches = searchLocations(text);
        if (matches.length > 0) {
          setSelectedRoute(matches[0]);
          toast.success(`Found ${matches[0].name}`);
        } else {
          toast.error("Could not find that location.");
        }
      },
      () => setIsListening(false),
      () => {
        setIsListening(false);
        toast.error("Voice input failed.");
      }
    );
  };

  const clearRoute = () => {
    setSelectedRoute(null);
    setQuery('');
    setResults(getAllLocations());
  };

  return (
    <div className="h-full flex gap-6">
      {/* Left Sidebar: Search & List */}
      <div className={`flex flex-col gap-4 transition-all duration-300 ${selectedRoute ? 'w-1/3' : 'w-full max-w-2xl mx-auto'}`}>
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h2 className="text-xl font-bold mb-4">Find a Location</h2>
          <div className="relative flex gap-2">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
              <input
                type="text"
                value={query}
                onChange={(e) => handleSearch(e.target.value)}
                placeholder="Search (e.g., Library, HOD Cabin)"
                className="w-full pl-12 pr-4 py-4 bg-slate-50 border border-slate-200 rounded-xl focus:border-blue-500 focus:outline-none text-lg"
              />
            </div>
            <button
              onClick={startVoiceSearch}
              className={`p-4 rounded-xl transition-colors ${
                isListening ? 'bg-red-50 text-red-600 border border-red-200 animate-pulse' : 'bg-slate-50 text-slate-600 border border-slate-200 hover:bg-slate-100'
              }`}
            >
              <Mic size={24} />
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto bg-white rounded-2xl shadow-sm border border-slate-200 p-2">
          {results.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-slate-400">
              <MapPin size={48} className="mb-2 opacity-50" />
              <p>No locations found</p>
            </div>
          ) : (
            <div className="space-y-1">
              {results.map((loc) => (
                <button
                  key={loc.id}
                  onClick={() => setSelectedRoute(loc)}
                  className={`w-full text-left p-4 rounded-xl flex items-center justify-between group transition-all ${
                    selectedRoute?.id === loc.id 
                      ? 'bg-blue-600 text-white shadow-md' 
                      : 'hover:bg-slate-50 text-slate-700'
                  }`}
                >
                  <div>
                    <div className="font-semibold text-lg">{loc.name}</div>
                    <div className={`text-sm ${selectedRoute?.id === loc.id ? 'text-blue-100' : 'text-slate-500'}`}>
                      {loc.floor}, {loc.block}
                    </div>
                  </div>
                  <ChevronRight size={20} className={`opacity-0 group-hover:opacity-100 transition-opacity ${selectedRoute?.id === loc.id ? 'text-white opacity-100' : 'text-slate-400'}`} />
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Right Content: Route Display */}
      {selectedRoute && (
        <div className="flex-1 flex flex-col gap-6 animate-in slide-in-from-right-10 duration-300">
          {/* Header Card */}
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex justify-between items-start">
            <div>
              <div className="flex items-center gap-2 text-blue-600 font-bold tracking-wider text-sm uppercase mb-1">
                <Navigation size={16} />
                Route Ready
              </div>
              <h1 className="text-3xl font-bold text-slate-900">{selectedRoute.name}</h1>
              <p className="text-slate-500 text-lg">{selectedRoute.floor}, {selectedRoute.block}</p>
            </div>
            <button onClick={clearRoute} className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-lg">
              <RotateCcw size={20} />
            </button>
          </div>

          <div className="flex-1 flex gap-6 min-h-0">
            {/* Map & Stats */}
            <div className="flex-1 flex flex-col gap-6">
              <div className="flex-1 bg-slate-100 rounded-2xl border border-slate-200 relative overflow-hidden flex items-center justify-center group">
                 {/* Placeholder for map image - simplified for code gen */}
                 <div className="absolute inset-0 bg-[url('https://picsum.photos/800/600')] bg-cover bg-center opacity-50 mix-blend-multiply grayscale group-hover:grayscale-0 transition-all duration-700"></div>
                 <div className="relative z-10 bg-white/90 backdrop-blur px-6 py-3 rounded-full shadow-lg font-mono text-sm border border-slate-200">
                   Interactive Map View
                 </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100 flex items-center gap-4">
                  <div className="bg-white p-3 rounded-full text-blue-600 shadow-sm">
                    <Footprints size={24} />
                  </div>
                  <div>
                    <div className="text-sm text-blue-600 font-medium">Distance</div>
                    <div className="text-2xl font-bold text-slate-900">{selectedRoute.distance} m</div>
                  </div>
                </div>
                <div className="bg-emerald-50 p-6 rounded-2xl border border-emerald-100 flex items-center gap-4">
                  <div className="bg-white p-3 rounded-full text-emerald-600 shadow-sm">
                    <Clock size={24} />
                  </div>
                  <div>
                    <div className="text-sm text-emerald-600 font-medium">Est. Time</div>
                    <div className="text-2xl font-bold text-slate-900">{selectedRoute.estimatedTime} min</div>
                  </div>
                </div>
              </div>
            </div>

            {/* Instructions & QR */}
            <div className="w-80 flex flex-col gap-6">
              <div className="flex-1 bg-white rounded-2xl shadow-sm border border-slate-200 p-6 overflow-y-auto">
                <h3 className="font-bold text-slate-900 mb-4 flex items-center gap-2">
                  <Navigation size={18} />
                  Steps
                </h3>
                <div className="space-y-6 relative before:absolute before:left-3.5 before:top-2 before:bottom-2 before:w-0.5 before:bg-slate-200">
                  {selectedRoute.steps.map((step, index) => (
                    <div key={index} className="relative flex gap-4">
                      <div className="flex-shrink-0 w-7 h-7 bg-blue-600 text-white rounded-full flex items-center justify-center text-xs font-bold z-10 shadow-sm ring-4 ring-white">
                        {index + 1}
                      </div>
                      <div>
                        <p className="font-medium text-slate-900">{step.instruction}</p>
                        {step.detail && <p className="text-sm text-slate-500 mt-0.5">{step.detail}</p>}
                      </div>
                    </div>
                  ))}
                </div>
              </div>

              <div className="bg-slate-900 text-white p-6 rounded-2xl shadow-lg flex flex-col items-center text-center gap-4">
                <div className="bg-white p-2 rounded-lg">
                  <QRCodeSVG 
                    value={`https://viet-campus.edu/nav?dest=${selectedRoute.id}`} 
                    size={120}
                  />
                </div>
                <div>
                  <h4 className="font-bold">Scan to Take Away</h4>
                  <p className="text-slate-400 text-sm mt-1">Get these directions on your mobile</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Directions;

import React, { useState, useMemo } from 'react';
import { CircleDollarSign, GraduationCap, Calendar, BookOpen, ChevronDown } from 'lucide-react';
import { FEES } from '../data/mockData';
import { FeeStructure } from '../types';

const Fees: React.FC = () => {
  const [selectedCourse, setSelectedCourse] = useState<string>('B.Tech');
  const [selectedBranch, setSelectedBranch] = useState<string>('CSE');
  const [selectedYear, setSelectedYear] = useState<string>('1st');

  const courses = Array.from(new Set(FEES.map(f => f.course)));
  const branches = Array.from(new Set(FEES.filter(f => f.course === selectedCourse).map(f => f.branch)));
  const years = Array.from(new Set(FEES.filter(f => f.course === selectedCourse && f.branch === selectedBranch).map(f => f.year)));

  // Ensure logical defaults when switching parent categories
  useMemo(() => {
    if (!branches.includes(selectedBranch)) setSelectedBranch(branches[0] || '');
    if (!years.includes(selectedYear)) setSelectedYear(years[0] || '');
  }, [selectedCourse, selectedBranch, branches, years, selectedYear]);

  const feeData: FeeStructure | undefined = FEES.find(
    f => f.course === selectedCourse && f.branch === selectedBranch && f.year === selectedYear
  );

  return (
    <div className="h-full flex flex-col items-center justify-center animate-in fade-in duration-500">
      <div className="w-full max-w-4xl">
        <div className="text-center mb-10">
          <h2 className="text-3xl font-bold text-slate-900 mb-2">Fee Structure Inquiry</h2>
          <p className="text-slate-500">Select your academic details to view the breakdown</p>
        </div>

        <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden flex flex-col md:flex-row">
          {/* Controls */}
          <div className="p-8 bg-slate-50 border-r border-slate-200 md:w-5/12 flex flex-col gap-6">
            <div>
              <label className="block text-sm font-semibold text-slate-500 uppercase tracking-wider mb-2">Course</label>
              <div className="relative">
                <select
                  value={selectedCourse}
                  onChange={(e) => setSelectedCourse(e.target.value)}
                  className="w-full appearance-none bg-white border border-slate-300 text-slate-900 text-lg rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent font-medium"
                >
                  {courses.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
                <ChevronDown className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
              </div>
            </div>

            <div>
              <label className="block text-sm font-semibold text-slate-500 uppercase tracking-wider mb-2">Branch</label>
              <div className="relative">
                <select
