          <div className="flex-1 flex gap-6 min-h-0">
            {/* Map & Stats */}
            <div className="flex-1 flex flex-col gap-6">
              <div className="flex-1 bg-slate-100 rounded-2xl border border-slate-200 relative overflow-hidden flex items-center justify-center group">
                 {selectedRoute.mapImage ? (
                   <>
                     <img 
                       src={selectedRoute.mapImage} 
                       alt={`${selectedRoute.name} Map`}
                       className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 hover:scale-105"
                     />
                     <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent pointer-events-none"></div>
                   </>
                 ) : (
                   <div className="absolute inset-0 bg-slate-200 flex flex-col items-center justify-center text-slate-400">
                     <MapPin size={64} className="mb-4 opacity-20" />
