        </div>

        {/* Search Bar - Show ONLY if !selectedRoute */}
        {!selectedRoute && (
            <div className="w-full max-w-3xl mx-auto relative z-20">
                <div className="relative flex gap-2 shadow-2xl rounded-2xl">
                    <div className="relative flex-1">
                        <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-slate-400" size={24} />
                        <input
                            type="text"
                            value={query}
                            onChange={(e) => handleSearch(e.target.value)}
                            placeholder="Search for anything (e.g., Principal, CSE HOD, Library)"
                            className="w-full pl-16 pr-4 py-5 bg-white text-slate-900 rounded-2xl focus:ring-4 focus:ring-blue-500/50 focus:outline-none text-xl font-medium shadow-inner"
