                                    <div>
                                        <div className="font-bold text-lg text-slate-800">{loc.name}</div>
                                        <div className="text-sm text-slate-500">{loc.block} • {loc.floor}</div>
                                    </div>
                                    <ArrowRight size={20} className="text-slate-300 group-hover:text-blue-600"/>
                                </button>
