import React, { useState, useEffect, useRef } from 'react';
import { Mic, X, Send, Bot, Loader2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { startListening } from '../services/speechService';
import { IntentType } from '../types';
import toast from 'react-hot-toast';

const Assistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [query, setQuery] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const navigate = useNavigate();

  useEffect(() => {
    if (isOpen && inputRef.current) {
      inputRef.current.focus();
    }
  }, [isOpen]);

  const handleVoiceInput = () => {
    if (isListening) return;
    setIsListening(true);
    setQuery(''); // Clear existing query
    startListening(
      (text) => {
        setQuery(text);
        processQuery(text);
      },
      () => setIsListening(false),
      (err) => {
        setIsListening(false);
        toast.error('Voice input failed. Please try again.');
      },
      (interimText) => {
        // Show text as user speaks
        setQuery(interimText);
      }
    );
  };

  const processQuery = async (text: string) => {
    setIsProcessing(true);
    const lowerText = text.toLowerCase();

    // Simple Intent Detection Logic
    let intent = IntentType.UNKNOWN;

    // Check for fee related keywords
    if (lowerText.includes('fee') || lowerText.includes('cost') || lowerText.includes('tuition') || lowerText.includes('price')) {
      intent = IntentType.FEE;
    }
    // Check for navigation related keywords
    else if (
      lowerText.includes('where') || 
      lowerText.includes('go to') || 
      lowerText.includes('direction') || 
      lowerText.includes('route') ||
      lowerText.includes('find')
    ) {
      intent = IntentType.NAVIGATE;
    }

    // Artificial delay to simulate "AI" thinking
    setTimeout(() => {
      setIsProcessing(false);
      setIsOpen(false);
      setQuery('');

      if (intent === IntentType.FEE) {
        toast.success("Opening Course Fees...");
        navigate('/fees');
        // Advanced: Could parse course name from query here and pass as state
      } else if (intent === IntentType.NAVIGATE) {
        toast.success("Opening Directions...");
        // Extract potential location
        const locationKeyword = text.replace(/go to|where is|find|direction to|directions for/gi, '').trim();
        navigate('/directions', { state: { initialQuery: locationKeyword } });
      } else {
        toast('I didn\'t quite catch that. Try asking for "Directions" or "Fees".', {
          icon: '🤖',
          duration: 4000
        });
      }
    }, 1000);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (query.trim()) processQuery(query);
  };

  return (
    <>
      {/* Trigger Button */}
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-8 right-8 p-4 rounded-full shadow-2xl transition-all duration-300 z-50 flex items-center gap-2 ${
          isOpen ? 'scale-0 opacity-0' : 'bg-blue-600 text-white hover:bg-blue-700 scale-100 opacity-100'
        }`}
      >
        <Bot size={32} />
        <span className="font-semibold pr-2">May I help you?</span>
      </button>

      {/* Modal/Popup */}
      {isOpen && (
        <div className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50 flex items-end justify-end sm:items-center sm:justify-center p-4">
          <div className="bg-white w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-200">
            {/* Header */}
            <div className="bg-gradient-to-r from-blue-600 to-blue-500 p-6 flex justify-between items-center text-white">
              <div className="flex items-center gap-3">
                <div className="bg-white/20 p-2 rounded-full">
                  <Bot size={24} />
                </div>
                <div>
                  <h3 className="font-bold text-lg">Virtual Assistant</h3>
                  <p className="text-blue-100 text-sm">Ask about fees or directions</p>
                </div>
              </div>
              <button onClick={() => setIsOpen(false)} className="hover:bg-white/20 p-2 rounded-full transition-colors">
                <X size={20} />
              </button>
            </div>

            {/* Body */}
            <div className="p-6">
              <div className="mb-6 space-y-2">
                <p className="text-slate-500 text-sm font-medium uppercase tracking-wider">Try asking</p>
                <div className="flex flex-wrap gap-2">
                  <button onClick={() => processQuery("What is the fee for CSE?")} className="px-4 py-2 bg-slate-100 hover:bg-blue-50 text-slate-700 rounded-lg text-sm transition-colors text-left">
                    "What is the fee for CSE?"
                  </button>
                  <button onClick={() => processQuery("Directions to Library")} className="px-4 py-2 bg-slate-100 hover:bg-blue-50 text-slate-700 rounded-lg text-sm transition-colors text-left">
                    "Directions to Library"
                  </button>
                  <button onClick={() => processQuery("Where is the Canteen?")} className="px-4 py-2 bg-slate-100 hover:bg-blue-50 text-slate-700 rounded-lg text-sm transition-colors text-left">
                    "Where is the Canteen?"
                  </button>
                </div>
              </div>

              <form onSubmit={handleSubmit} className="relative">
                <input
                  ref={inputRef}
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder={isListening ? "Listening..." : "Type or speak your request..."}
                  className={`w-full pl-4 pr-24 py-4 bg-slate-50 border-2 rounded-xl focus:outline-none text-lg transition-colors ${
                    isListening ? 'border-blue-500 bg-blue-50' : 'border-slate-200 focus:border-blue-500'
                  }`}
                />
                <div className="absolute right-2 top-2 bottom-2 flex gap-1">
                  <button
                    type="button"
                    onClick={handleVoiceInput}
                    className={`p-3 rounded-lg transition-colors ${
                      isListening ? 'bg-red-100 text-red-600 animate-pulse' : 'hover:bg-slate-200 text-slate-500'
                    }`}
                  >
                    <Mic size={24} />
                  </button>
                  <button
                    type="submit"
                    disabled={!query.trim() || isProcessing}
                    className="p-3 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    {isProcessing ? <Loader2 size={24} className="animate-spin" /> : <Send size={24} />}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default Assistant;

// Types for the Web Speech API
interface SpeechRecognition extends EventTarget {
  continuous: boolean;
  interimResults: boolean;
  lang: string;
  start(): void;
  stop(): void;
  abort(): void;
  onstart: (event: Event) => void;
  onend: (event: Event) => void;
  onerror: (event: any) => void;
  onresult: (event: any) => void;
}

interface Window {
  SpeechRecognition: any;
  webkitSpeechRecognition: any;
}

export const startListening = (
  onResult: (text: string) => void,
  onEnd: () => void,
  onError: (error: string) => void,
  onInterim?: (text: string) => void
) => {
  const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;

  if (!SpeechRecognition) {
    onError('Speech recognition not supported in this browser.');
    return null;
  }

  const recognition: SpeechRecognition = new SpeechRecognition();
  recognition.continuous = false;
  recognition.interimResults = true; // Enable interim results for real-time feedback
  recognition.lang = 'en-US';

  recognition.onstart = () => {
    // console.log('Listening started...');
  };

  recognition.onresult = (event: any) => {
    let interimTranscript = '';
    let finalTranscript = '';

    for (let i = event.resultIndex; i < event.results.length; ++i) {
      if (event.results[i].isFinal) {
        finalTranscript += event.results[i][0].transcript;
      } else {
        interimTranscript += event.results[i][0].transcript;
      }
    }

    // Send interim results if available
    if (interimTranscript && onInterim) {
      onInterim(interimTranscript);
    }

    // Send final result
    if (finalTranscript) {
      onResult(finalTranscript);
    }
  };

  recognition.onerror = (event: any) => {
    // Ignore 'no-speech' error if it just means silence before end
    if (event.error === 'no-speech') {
        return; 
    }

    // Ignore aborted errors (usually user clicking mic button again to stop)
    if (event.error === 'aborted') {
        return;
    }

    let errorMessage = event.error;

    // Map common errors to user-friendly messages
    if (event.error === 'network') {
        errorMessage = 'Network error. Internet is required for voice search.';
    } else if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
        errorMessage = 'Microphone access blocked. Check permissions.';
    }

    onError(errorMessage);
  };

  recognition.onend = () => {
    onEnd();
  };

  try {
    recognition.start();
    return recognition;
  } catch (e) {
    onError('Failed to start recognition');
    return null;
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Search, MapPin, Navigation, Clock, Footprints, Mic, ChevronRight, RotateCcw, ArrowLeft, ArrowRight, Building, Users, Briefcase, GraduationCap, Coffee, Home, X } from 'lucide-react';
import { QRCodeSVG } from 'qrcode.react';
import { useLocation, useNavigate } from 'react-router-dom';
import Fuse from 'fuse.js';
import { searchLocations } from '../services/searchService';
import { startListening } from '../services/speechService';
import { LocationData, LocationCategory } from '../types';
import { LOCATIONS } from '../data/mockData';
import toast from 'react-hot-toast';

// Types for navigation state
interface NavState {
  block?: string;
  category?: LocationCategory;
  department?: string;
}

// Full Name Mapping for Fuzzy Search
const DEPT_FULL_NAMES: Record<string, string> = {
  'CSE': 'Computer Science & Engineering',
  'ECE': 'Electronics & Communication',
  'EEE': 'Electrical & Electronics',
  'MECH': 'Mechanical Engineering',
  'CIVIL': 'Civil Engineering',
  'Common': 'General & Common Facilities'
};

const Directions: React.FC = () => {
  const routerLoc = useLocation();
  const navigate = useNavigate();

  // Search State
  const [query, setQuery] = useState('');
  const [searchResults, setSearchResults] = useState<LocationData[]>([]);
  const [isListening, setIsListening] = useState(false);

  // Hierarchical Browsing State
  const [navState, setNavState] = useState<NavState>({});
  const [deptFilter, setDeptFilter] = useState('');

  // Final Selection
  const [selectedRoute, setSelectedRoute] = useState<LocationData | null>(null);

  // Constants derived from data
  const BLOCKS = Array.from(new Set(LOCATIONS.map(l => l.block)));

  // Handle intent passing from Assistant
  useEffect(() => {
    if (routerLoc.state && (routerLoc.state as any).initialQuery) {
      const initQ = (routerLoc.state as any).initialQuery;
      // Do not setQuery(initQ) here to prevent dropdown from opening over result
      const matches = searchLocations(initQ);
      if (matches.length > 0) {
        setSelectedRoute(matches[0]);
      } else {
        setQuery(initQ); // Populate so user can correct it
        handleSearch(initQ);
        toast.error("Location not found.");
      }
    }
  }, [routerLoc.state]);

  const handleSearch = (text: string) => {
    setQuery(text);
    if (text.trim() === '') {
      setSearchResults([]);
      return;
    }
    const matches = searchLocations(text);
    setSearchResults(matches);
  };

  const startVoiceSearch = () => {
    if (isListening) return;
    setIsListening(true);
    setQuery(''); // Clear previous query

    startListening(
      (text) => {
        // On Final Result
        handleSearch(text);
        const matches = searchLocations(text);
        if (matches.length > 0) {
          setSelectedRoute(matches[0]);
          setQuery(''); // Clear query to hide dropdown
          setSearchResults([]);
          toast.success(`Found ${matches[0].name}`);
        } else {
          toast.error("Could not find that location.");
        }
      },
      () => setIsListening(false), // On End
      (error) => {
        setIsListening(false);
        toast.error(error); // Display cleaned error from service
      },
      (interimText) => {
        // On Interim Result (Real-time updates)
        setQuery(interimText);
      }
    );
  };

  const handleSelectLocation = (loc: LocationData) => {
    setSelectedRoute(loc);
    setQuery(''); // Clear query to hide dropdown
    setSearchResults([]);
  };

  const clearRoute = () => {
    setSelectedRoute(null);
    setQuery('');
    setSearchResults([]);
    setNavState({});
    setDeptFilter('');
  };

  const resetNavigation = () => {
    setNavState({});
    setQuery('');
    setSearchResults([]);
    setDeptFilter('');
  };

  // --- Filtering Logic for Browsing ---
  const getFilteredLocations = () => {
    return LOCATIONS.filter(loc => {
      if (navState.block && loc.block !== navState.block) return false;
      if (navState.category && loc.category !== navState.category) return false;
      if (navState.department && loc.department !== navState.department) return false;
      return true;
    });
  };

  // --- Render Helpers ---

  // 1. Block Selection
  const renderBlockSelection = () => (
    <div className="grid grid-cols-2 md:grid-cols-3 gap-6 animate-in slide-in-from-bottom-4 duration-500">
      {BLOCKS.map(block => (
        <button
          key={block}
          onClick={() => setNavState({ ...navState, block })}
          className="bg-white/95 backdrop-blur-sm p-8 rounded-2xl shadow-lg border border-slate-200 hover:border-blue-500 hover:shadow-blue-500/20 transition-all group text-left"
        >
          <div className="bg-blue-100 w-14 h-14 rounded-full flex items-center justify-center text-blue-600 mb-4 group-hover:bg-blue-600 group-hover:text-white transition-colors">
            {block.includes('MBA') ? <Briefcase size={28} /> : 
             block.includes('Grounds') ? <Coffee size={28} /> : 
             <Building size={28} />}
