                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                // --- SHOW HIERARCHY BROWSER ---
                <div className="w-full max-w-5xl mx-auto">
                    {/* Breadcrumbs */}
                    {(navState.block || navState.category) && renderBreadcrumbs()}

