import React, { useState, useEffect, useRef } from 'react';
import { Mic, X, Send, Bot, Loader2, Sparkles, User, MapPin, Ticket } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { startListening } from '../services/speechService';
import { searchLocations } from '../services/searchService';
import { LOCATIONS, FEES } from '../data/mockData';
import { GoogleGenAI, Type, FunctionDeclaration, Tool } from "@google/genai";
import toast from 'react-hot-toast';

// --- Configuration ---
const MODEL_NAME = 'gemini-2.5-flash-latest';

// --- System Instruction ---
const locationNames = LOCATIONS.map(l => l.name).join(", ");
const feeCourses = Array.from(new Set(FEES.map(f => f.course))).join(", ");

const SYSTEM_INSTRUCTION = `You are "Vi", the intelligent AI assistant for the Visakha Institute of Engineering and Technology (VIET) campus kiosk.
Your goal is to assist students, parents, and visitors in a friendly, concise, and professional manner.
You have access to real-time app controls via tools.

**Knowledge Base:**
- Locations: ${locationNames}.
- Courses offered: ${feeCourses}.

**Guidelines:**
1. **Be Concise**: Keep answers under 40 words. This is a kiosk.
2. **Be Helpful**: If a user greets you, greet back warmly.
3. **Use Tools**: 
   - If the user implies wanting to go somewhere (e.g., "Where is the library?", "Take me to the Principal"), use 'navigate'.
   - If the user asks about money, tuition, or seats (e.g., "Fee for CSE?", "How much for MBA?"), use 'showFees'.
4. **Fallback**: If you don't know, apologize and suggest asking for "Directions" or "Fees".
`;

// --- Tool Definitions ---
const tools: Tool[] = [
  {
    functionDeclarations: [
      {
        name: "navigate",
        description: "Navigate to a specific location on campus.",
        parameters: {
          type: Type.OBJECT,
          properties: {
            locationName: { type: Type.STRING, description: "The name of the location to find (e.g. 'Library', 'CSE HOD')." }
          },
          required: ["locationName"]
        }
      },
      {
        name: "showFees",
        description: "Show the fee structure page, optionally for a specific course.",
        parameters: {
          type: Type.OBJECT,
          properties: {
            course: { type: Type.STRING, description: "The course name (e.g. B.Tech, MBA)" },
            branch: { type: Type.STRING, description: "The branch name (e.g. CSE, ECE)" }
          },
        }
      }
    ]
  }
];

interface Message {
  id: string;
  role: 'user' | 'model';
  text: string;
  isTool?: boolean;
}

const Assistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { id: 'init', role: 'model', text: "Hello! I'm Vi. I can help you find your way or check fees. How can I help?" }
  ]);
  const [inputValue, setInputValue] = useState('');
  const [isListening, setIsListening] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const navigate = useNavigate();

  // Gemini Client
  // Note: API_KEY is assumed to be available in process.env as per environment config
  const aiRef = useRef<GoogleGenAI | null>(null);
  const chatRef = useRef<any>(null);

  useEffect(() => {
    try {
        if (process.env.API_KEY) {
            aiRef.current = new GoogleGenAI({ apiKey: process.env.API_KEY });
        } else {
            console.warn("Gemini API Key missing. Assistant will act in offline mock mode.");
        }
    } catch (e) {
        console.error("Failed to init AI", e);
    }
  }, []);

  // Initialize Chat Session
  const initChat = async () => {
    if (!aiRef.current) return;
    try {
        chatRef.current = aiRef.current.chats.create({
            model: MODEL_NAME,
            config: {
                systemInstruction: SYSTEM_INSTRUCTION,
                tools: tools,
            }
        });
    } catch (e) {
        console.error("Chat init error", e);
    }
  };

  useEffect(() => {
    if (isOpen) {
        if (!chatRef.current) initChat();
        setTimeout(() => inputRef.current?.focus(), 100);
        scrollToBottom();
    }
  }, [isOpen]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleVoiceInput = () => {
    if (isListening) return;
    setIsListening(true);
    startListening(
      (text) => {
        setInputValue(text);
        handleSubmit(undefined, text);
      },
      () => setIsListening(false),
      (err) => {
        setIsListening(false);
        toast.error("Voice input failed. Please type.");
      },
      (interim) => setInputValue(interim)
    );
  };

  const executeTool = (name: string, args: any) => {
    console.log("Executing tool:", name, args);
    let result = "Action performed.";

    if (name === 'navigate') {
        const matches = searchLocations(args.locationName);
        if (matches.length > 0) {
            navigate('/directions', { state: { initialQuery: matches[0].name } });
            result = `Navigated to ${matches[0].name}.`;
            // Optional: Close assistant on successful navigation if desired, but conversational is better
            // setIsOpen(false); 
        } else {
            result = `Location '${args.locationName}' not found on map.`;
        }
    } else if (name === 'showFees') {
        navigate('/fees');
        result = "Opened Fee Structure page.";
    }

    return { result };
  };

  const handleSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const text = overrideText || inputValue;
    if (!text.trim() || isProcessing) return;

    // 1. Add User Message
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsProcessing(true);

    try {
        // Fallback for no API key (Offline Demo)
        if (!chatRef.current) {
             setTimeout(() => {
                const lower = text.toLowerCase();
                let reply = "I'm having trouble connecting to my brain right now.";
                if (lower.includes('hello')) reply = "Hi there! I'm operating in offline mode.";
                if (lower.includes('fee')) { executeTool('showFees', {}); reply = "Opening fees for you."; }
                if (lower.includes('where') || lower.includes('go')) { 
                    executeTool('navigate', { locationName: text.replace(/go to|where is/gi, '').trim() }); 
                    reply = "Looking that up..."; 
                }
                setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: reply }]);
                setIsProcessing(false);
             }, 1000);
             return;
        }

        // 2. Send to Gemini
        const response = await chatRef.current.sendMessage({ message: text });

        // 3. Handle Tool Calls Loop
        let finalResponseText = response.text || "";

        // Check for function calls in the response candidates
        const candidates = response.candidates || [];
        const functionCalls = candidates[0]?.content?.parts?.filter((p: any) => p.functionCall).map((p: any) => p.functionCall);

        if (functionCalls && functionCalls.length > 0) {
            const functionResponses = [];

            // Execute all tools
            for (const call of functionCalls) {
                const result = executeTool(call.name, call.args);
                functionResponses.push({
                    id: call.id,
                    name: call.name,
                    response: { result: result }
                });
            }

            // Send tool output back to model
            const toolResponse = await chatRef.current.sendMessage(
                { 
                    parts: [{ functionResponse: { name: functionCalls[0].name, response: { result: functionResponses[0].response.result } } }]
                    // Note: The SDK might handle array of function responses differently, but usually we send them back.
                    // For simplicity in this kiosk, we'll just assume one turn of tools is enough or the model gave text with it.
                }
            );
            finalResponseText = toolResponse.text;
        }

        // 4. Add Model Message
        if (finalResponseText) {
            setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: finalResponseText }]);
        }

    } catch (err) {
        console.error("AI Error", err);
        setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "Sorry, I encountered a connection error. Please try again." }]);
    } finally {
        setIsProcessing(false);
    }
  };

  return (
    <>
      {/* Floating Action Button */}
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-6 right-6 p-0 w-16 h-16 rounded-full shadow-2xl transition-all duration-300 z-50 flex items-center justify-center group ${
          isOpen ? 'scale-0 opacity-0' : 'bg-gradient-to-r from-blue-600 to-indigo-600 scale-100 opacity-100 hover:scale-110'
        }`}
      >
        <div className="absolute inset-0 bg-white rounded-full opacity-20 animate-ping"></div>
        <Bot size={32} className="text-white relative z-10" />
        <span className="absolute right-full mr-4 bg-white px-3 py-1 rounded-lg shadow-md text-sm font-bold text-slate-700 whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity">
            Ask AI Assistant
        </span>
      </button>

      {/* Chat Interface Modal */}
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center sm:items-center sm:p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full sm:max-w-md h-[80vh] sm:h-[600px] sm:rounded-3xl shadow-2xl overflow-hidden flex flex-col relative animate-in slide-in-from-bottom-10 zoom-in-95 duration-300">

            {/* Header */}
            <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-4 flex items-center justify-between shrink-0">
                <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-white/20 backdrop-blur rounded-full flex items-center justify-center text-white border border-white/30">
                        <Sparkles size={20} />
                    </div>
                    <div>
                        <h3 className="font-bold text-white text-lg leading-tight">Vi Assistant</h3>
                        <div className="flex items-center gap-1.5">
                            <span className="w-2 h-2 rounded-full bg-green-400 animate-pulse"></span>
                            <p className="text-blue-100 text-xs font-medium">Online</p>
                        </div>
                    </div>
                </div>
                <button 
                    onClick={() => setIsOpen(false)}
                    className="w-8 h-8 flex items-center justify-center rounded-full bg-white/10 text-white hover:bg-white/20 transition-colors"
                >
                    <X size={18} />
                </button>
            </div>

            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 scroll-smooth">
                {messages.map((msg) => (
                    <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                        <div className={`flex max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'} gap-2 items-end`}>
                            {/* Avatar */}
                            <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center text-xs font-bold ${
                                msg.role === 'user' ? 'bg-indigo-100 text-indigo-700' : 'bg-blue-600 text-white shadow-md'
                            }`}>
                                {msg.role === 'user' ? <User size={14} /> : <Bot size={16} />}
                            </div>

                            {/* Bubble */}
                            <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
                                msg.role === 'user' 
                                    ? 'bg-white text-slate-800 rounded-br-none border border-slate-100' 
                                    : 'bg-blue-600 text-white rounded-bl-none'
                            }`}>
                                {msg.text}
                            </div>
                        </div>
                    </div>
                ))}

                {isProcessing && (
                    <div className="flex justify-start">
                        <div className="flex max-w-[85%] gap-2 items-end">
                            <div className="w-8 h-8 rounded-full bg-blue-600 text-white flex items-center justify-center shadow-md">
                                <Loader2 size={16} className="animate-spin" />
                            </div>
                            <div className="px-4 py-3 bg-white border border-slate-100 rounded-2xl rounded-bl-none text-slate-500 text-xs font-medium shadow-sm flex items-center gap-1">
                                <span className="w-1 h-1 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                                <span className="w-1 h-1 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                                <span className="w-1 h-1 bg-slate-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
                            </div>
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            {/* Input Area */}
            <div className="p-4 bg-white border-t border-slate-100 shrink-0">
                <form 
                    onSubmit={(e) => handleSubmit(e)}
                    className="relative flex items-center gap-2"
                >
                    <div className="relative flex-1">
                        <input
                            ref={inputRef}
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                            placeholder="Type a message..."
                            className="w-full pl-4 pr-10 py-3 bg-slate-100 border-transparent focus:bg-white border focus:border-blue-500 rounded-xl focus:outline-none transition-all text-slate-800 placeholder:text-slate-400"
                            disabled={isProcessing}
                        />
                        <button
                            type="button"
                            onClick={handleVoiceInput}
                            className={`absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-lg transition-colors ${
                                isListening ? 'bg-red-500 text-white animate-pulse' : 'text-slate-400 hover:text-slate-600'
                            }`}
                        >
                            <Mic size={20} />
                        </button>
                    </div>
                    <button
                        type="submit"
                        disabled={!inputValue.trim() || isProcessing}
                        className="p-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 disabled:opacity-50 disabled:hover:bg-blue-600 transition-colors shadow-md flex items-center justify-center"
                    >
                        <Send size={20} className={isProcessing ? 'opacity-0' : 'opacity-100'} />
                        {isProcessing && <Loader2 size={20} className="absolute animate-spin" />}
                    </button>
                </form>
            </div>

          </div>
        </div>
      )}
    </>
  );
};

