export interface NavStep {
  instruction: string;
  detail?: string;
  icon?: 'turn-left' | 'turn-right' | 'straight' | 'stairs-up' | 'stairs-down' | 'destination';
}

export type LocationCategory = 'administrative' | 'academic' | 'amenity' | 'other';

export interface LocationData {
  id: string;
  name: string;
  block: string;
  floor: string;
  category: LocationCategory;
  department?: string; // e.g., 'ECE', 'CSE', 'Civil'
  aliases: string[];
  distance: number; // meters
  estimatedTime: number; // minutes
  steps: NavStep[];
  mapImage?: string;
}

export interface FeeStructure {
  id: string;
  course: string;
  branch: string;
  seats: number;
  annualFee: number;
  description?: string;
}

// --- Agent Types ---

export enum IntentType {
  NAVIGATE = 'NAVIGATE',
  FEE = 'FEE',
  GREETING = 'GREETING',
  UNKNOWN = 'UNKNOWN',
  CLEAR = 'CLEAR'
}

export interface ChatMessage {
  id: string;
  sender: 'user' | 'assistant';
  text: string;
  isTyping?: boolean;
  timestamp: number;
}

export interface AgentContext {
  awaitingClarification?: boolean;
  clarificationType?: 'FEE_COURSE' | 'FEE_BRANCH' | 'LOCATION_CONFIRM';
  partialFeeData?: {
    course?: string;
    branch?: string;
  };
  potentialLocation?: LocationData;
}

export interface AgentAction {
  type: 'NAVIGATE' | 'SHOW_FEES' | 'NONE';
  payload?: any;
}

export interface AgentResponse {
  message: string;
  action: AgentAction;
  updatedContext: AgentContext;
}

import { IntentType, AgentContext, AgentResponse, LocationData } from '../types';
import { searchLocations } from './searchService';
import { FEES } from '../data/mockData';

// --- Constants & Patterns ---
const GREETINGS = ['hi', 'hello', 'hey', 'good morning', 'good afternoon', 'hola'];
const NAV_KEYWORDS = ['where', 'go', 'find', 'navigate', 'direction', 'route', 'way', 'location', 'map'];
const FEE_KEYWORDS = ['fee', 'cost', 'price', 'tuition', 'money', 'pay', 'seat'];

// --- Helper: Intent Detection ---
const detectIntent = (text: string): IntentType => {
  const lower = text.toLowerCase();

  if (lower === 'clear' || lower === 'reset') return IntentType.CLEAR;
  if (GREETINGS.some(g => lower.startsWith(g))) return IntentType.GREETING;
  if (FEE_KEYWORDS.some(k => lower.includes(k))) return IntentType.FEE;

  // Navigation is the fallback if keywords match OR if it looks like a location search
  if (NAV_KEYWORDS.some(k => lower.includes(k))) return IntentType.NAVIGATE;

  return IntentType.UNKNOWN;
};

// --- Helper: Entity Extraction ---
const extractFeeEntities = (text: string) => {
  const lower = text.toLowerCase();

  // Detect Course
  let course: string | undefined;
  if (lower.includes('b.tech') || lower.includes('btech')) course = 'B.Tech';
  else if (lower.includes('mba')) course = 'MBA';
  else if (lower.includes('diploma')) course = 'Diploma';

  // Detect Branch
  let branch: string | undefined;
  if (lower.includes('cse') || lower.includes('computer')) branch = 'CSE';
  else if (lower.includes('ece') || lower.includes('electronics')) branch = 'ECE';
  else if (lower.includes('eee') || lower.includes('electrical')) branch = 'EEE';
  else if (lower.includes('mech')) branch = 'MECH';
  else if (lower.includes('civil')) branch = 'CIVIL';

  return { course, branch };
};

// --- Core: Conversation Manager ---
export const processUserMessage = (
  text: string, 
  context: AgentContext
): AgentResponse => {
  const intent = detectIntent(text);
  const lowerText = text.toLowerCase();

  // 1. Handle Clarifications (Multi-turn)
  if (context.awaitingClarification) {
    if (context.clarificationType === 'FEE_COURSE') {
       const extracted = extractFeeEntities(text);
       if (extracted.course) {
         return handleFeeFlow({ ...context.partialFeeData, course: extracted.course }, { ...context, awaitingClarification: false });
       }
       return {
         message: "I didn't catch that. Please say B.Tech, MBA, or Diploma.",
         action: { type: 'NONE' },
         updatedContext: context
       };
    }

    if (context.clarificationType === 'FEE_BRANCH') {
       const extracted = extractFeeEntities(text);
       if (extracted.branch) {
         return handleFeeFlow({ ...context.partialFeeData, branch: extracted.branch }, { ...context, awaitingClarification: false });
       }
       // Allow skipping branch if they just want general info? For now enforce valid branch or generic.
       return {
         message: "Could you specify the branch? (CSE, ECE, EEE, MECH)",
         action: { type: 'NONE' },
         updatedContext: context
       };
    }

    if (context.clarificationType === 'LOCATION_CONFIRM') {
        if (lowerText.includes('yes') || lowerText.includes('yeah') || lowerText.includes('ok')) {
             return {
                message: `Navigating to ${context.potentialLocation?.name}...`,
                action: { type: 'NAVIGATE', payload: { initialQuery: context.potentialLocation?.name } },
                updatedContext: {} // Reset
             };
        } else {
            return {
                message: "Okay, let's try again. Where would you like to go?",
                action: { type: 'NONE' },
                updatedContext: {}
            };
        }
    }
  }

  // 2. Handle New Intents
  switch (intent) {
    case IntentType.GREETING:
      return {
        message: "Hello! I can help you find locations or check fee structures. What do you need?",
        action: { type: 'NONE' },
        updatedContext: context
      };

    case IntentType.CLEAR:
      return {
        message: "Conversation reset. How can I help?",
        action: { type: 'NONE' },
        updatedContext: {}
      };

    case IntentType.FEE:
      const entities = extractFeeEntities(text);
      return handleFeeFlow(entities, context);

    case IntentType.NAVIGATE:
    case IntentType.UNKNOWN: // Treat unknown as potential navigation search
      // Remove keywords to isolate the location name
      const cleanQuery = text.replace(/where is|go to|find|navigate to|show me|the/gi, '').trim();

      if (cleanQuery.length < 2) {
          return {
              message: "I'm listening. Where do you want to go, or what fees are you looking for?",
              action: { type: 'NONE' },
              updatedContext: context
          };
      }

      const matches = searchLocations(cleanQuery);

      if (matches.length > 0) {
        // High confidence match (Fuse.js usually sorts by score)
        const topMatch = matches[0];

        // If query is very short or ambiguous, maybe confirm? 
        // For kiosk, speed is key. If distinct match, just go.
        return {
           message: `Found it! Taking you to ${topMatch.name}.`,
           action: { type: 'NAVIGATE', payload: { initialQuery: topMatch.name } },
           updatedContext: {}
        };
      } else {
        return {
          message: "I couldn't find that location. Try searching for a department (e.g., 'CSE') or amenity (e.g., 'Canteen').",
          action: { type: 'NONE' },
          updatedContext: context
        };
      }
  }

  return {
    message: "I'm not sure I understand. Try asking for 'Fees' or 'Directions'.",
    action: { type: 'NONE' },
    updatedContext: context
  };
};

// --- Sub-Flow: Fees ---
function handleFeeFlow(data: { course?: string; branch?: string }, currentContext: AgentContext): AgentResponse {
   // 1. Missing Course
   if (!data.course) {
     return {
       message: "Which course are you interested in? (B.Tech, MBA, Diploma)",
       action: { type: 'NONE' },
       updatedContext: {
         ...currentContext,
         awaitingClarification: true,
         clarificationType: 'FEE_COURSE',
         partialFeeData: data
       }
     };
   }

   // 2. Missing Branch (Only for B.Tech/Diploma usually, MBA has 'General')
   // Simple check: if we have course but no branch, ask for branch
   if (!data.branch) {
     return {
       message: `For ${data.course}, which branch? (e.g., CSE, ECE)`,
       action: { type: 'NONE' },
       updatedContext: {
         ...currentContext,
         awaitingClarification: true,
         clarificationType: 'FEE_BRANCH',
         partialFeeData: data
       }
     };
   }

   // 3. All Good
   return {
     message: `Opening fee structure for ${data.course} - ${data.branch}...`,
     action: { type: 'SHOW_FEES' }, // The view will handle state if we pass it, but for now just routing
     updatedContext: {}
   };
}

import React, { useState, useEffect, useRef } from 'react';
import { Mic, X, Send, Bot, Sparkles, User, RefreshCw, ChevronDown } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { startListening } from '../services/speechService';
import { processUserMessage } from '../services/agentService';
import { ChatMessage, AgentContext } from '../types';
import toast from 'react-hot-toast';

const Assistant: React.FC = () => {
  const navigate = useNavigate();
  const [isOpen, setIsOpen] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [inputValue, setInputValue] = useState('');

  // Conversation State
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'assistant', text: "Hi! I'm Vi. I can help with Directions or Fees.", timestamp: Date.now() }
  ]);
  const [agentContext, setAgentContext] = useState<AgentContext>({});
  const [isTyping, setIsTyping] = useState(false);

  // Refs
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Auto-scroll
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  useEffect(() => {
    if (isOpen) {
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  }, [isOpen]);

  // Handle Voice
  const handleVoiceInput = () => {
    if (isListening) return;
    setIsListening(true);
    startListening(
      (text) => {
        setInputValue(text);
        handleSubmit(undefined, text);
      },
      () => setIsListening(false),
      (err) => {
        setIsListening(false);
        toast.error("Could not hear you. Please try typing.");
      },
      (interim) => setInputValue(interim)
    );
  };

  // Handle Submit
  const handleSubmit = async (e?: React.FormEvent, overrideText?: string) => {
    e?.preventDefault();
    const text = overrideText || inputValue;
    if (!text.trim()) return;

    // 1. Add User Message
    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      sender: 'user',
      text: text,
      timestamp: Date.now()
    };
    setMessages(prev => [...prev, userMsg]);
    setInputValue('');
    setIsTyping(true);

    // 2. Simulate AI Delay (600ms - 1200ms)
    const delay = Math.floor(Math.random() * 600) + 600;

    setTimeout(() => {
       // 3. Process via Agent Service
       const response = processUserMessage(text, agentContext);

       setIsTyping(false);
       setAgentContext(response.updatedContext);

       const botMsg: ChatMessage = {
         id: (Date.now() + 1).toString(),
         sender: 'assistant',
         text: response.message,
         timestamp: Date.now()
       };
       setMessages(prev => [...prev, botMsg]);

       // 4. Perform Action if any
       if (response.action.type === 'NAVIGATE') {
         setTimeout(() => {
            setIsOpen(false);
            navigate('/directions', { state: response.action.payload });
         }, 1500); // Allow user to read message first
       } else if (response.action.type === 'SHOW_FEES') {
         setTimeout(() => {
            setIsOpen(false);
            navigate('/fees');
         }, 1500);
       }

    }, delay);
  };

  const handleReset = () => {
    setMessages([{ id: Date.now().toString(), sender: 'assistant', text: "Conversation cleared. How can I help?", timestamp: Date.now() }]);
    setAgentContext({});
  };

  return (
    <>
      {/* Floating Action Button */}
      <button
        onClick={() => setIsOpen(true)}
        className={`fixed bottom-6 right-6 w-16 h-16 rounded-full shadow-2xl transition-all duration-300 z-50 flex items-center justify-center group ${
          isOpen ? 'scale-0 opacity-0' : 'bg-gradient-to-tr from-blue-600 to-indigo-600 scale-100 opacity-100 hover:scale-110'
        }`}
      >
        <div className="absolute inset-0 bg-white rounded-full opacity-20 animate-ping"></div>
        <Bot size={32} className="text-white relative z-10" />
        <span className="absolute right-full mr-4 bg-white px-3 py-1 rounded-lg shadow-md text-sm font-bold text-slate-700 whitespace-nowrap opacity-0 group-hover:opacity-100 transition-opacity">
            Need Help?
        </span>
      </button>

      {/* Chat Window Modal */}
      {isOpen && (
        <div className="fixed inset-0 z-50 flex items-end justify-center sm:items-center sm:p-4 bg-black/40 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full sm:max-w-md h-[85vh] sm:h-[600px] sm:rounded-3xl shadow-2xl overflow-hidden flex flex-col relative animate-in slide-in-from-bottom-10 zoom-in-95 duration-300 border border-white/20">

            {/* Header */}
            <div className="bg-gradient-to-r from-blue-600 to-indigo-600 p-4 flex items-center justify-between shrink-0 shadow-md z-10">
