  return (
    <div className="flex flex-col h-full relative">
       {/* Voice Modal Component */}
       <VoiceSearchModal 
           isOpen={showVoiceModal} 
           onClose={() => setShowVoiceModal(false)} 
           onResult={handleVoiceResult} 
