        <button onClick={() => setNavState({ ...navState, mainBlockSection: 'academic' })} className="bg-white p-8 rounded-2xl shadow-lg border border-slate-200 hover:border-blue-500 transition-all text-left flex items-center gap-4 group">
             <div className="bg-blue-100 p-4 rounded-full text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                <GraduationCap size={32} />
             </div>
             <div>
                <h3 className="text-xl font-bold text-slate-900">Academic Departments</h3>
                <p className="text-slate-500">B.Tech & M.Tech Departments</p>
